import{_ as a,H as t,f as i,i as e}from"./chunks/framework.DbTCwA-u.js";const k=JSON.parse('{"title":"Голографические питомцы","description":"Как настроить неймтеги питомцев в pets.yml.","frontmatter":{"title":"Голографические питомцы","description":"Как настроить неймтеги питомцев в pets.yml."},"headers":[],"relativePath":"ru/config/pets.md","filePath":"ru/config/pets.md"}'),l={name:"ru/config/pets.md"};function n(p,s,h,o,d,r){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="голографические-питомцы-pets-yml" tabindex="-1">Голографические питомцы (pets.yml) <a class="header-anchor" href="#голографические-питомцы-pets-yml" aria-label="Permalink to &quot;Голографические питомцы (pets.yml)&quot;">​</a></h1><p>Система питомцев — одна из самых инновационных функций EligiusNametag. С её помощью любой волк, попугай или кошка, прирученные игроком, получат плавающий голографический неймтег, который плавно следует за питомцем.</p><h3 id="базовая-конфигурация" tabindex="-1">Базовая конфигурация <a class="header-anchor" href="#базовая-конфигурация" aria-label="Permalink to &quot;Базовая конфигурация&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  show_unnamed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li>Если <code>show_unnamed</code> установлено на <code>true</code>, даже у обычного прирученного волка будет текстовая голограмма.</li><li>Если установлено на <code>false</code>, только питомцы, которых игрок переименовывает с помощью <strong>Наковальни</strong> (ванильная Бирка), активируют голографическую систему, чтобы сохранить более ванильный стиль на общем сервере.</li></ul><h3 id="дизаин-строк" tabindex="-1">Дизайн строк <a class="header-anchor" href="#дизаин-строк" aria-label="Permalink to &quot;Дизайн строк&quot;">​</a></h3><p>Используйте <code>&lt;DISPLAYNAME&gt;</code>, чтобы показать имя, которое игрок дал ему в наковальне, и <code>&lt;PLAYER&gt;</code>, чтобы процитировать владельца.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gray&gt;Питомец &lt;PLAYER&gt;&lt;/gray&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;DISPLAYNAME&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><h3 id="🐾-самыи-большои-секрет" tabindex="-1">🐾 Самый большой секрет! <a class="header-anchor" href="#🐾-самыи-большои-секрет" aria-label="Permalink to &quot;🐾 Самый большой секрет!&quot;">​</a></h3><p>Питомцы <strong>наследуют</strong> дизайн ранга Vault своего владельца. Это означает, что если владелец кошки имеет ранг &quot;Admin&quot; в <code>players.yml</code>, и ранг Admin имеет красный текст и значок огня, <strong>кошка также будет показывать красный текст и значок огня</strong> в своей переменной группы (если вы настроите это так, пересекая переменные PAPI или права LuckPerms на уровне узла <code>&lt;PLAYER&gt;</code>).</p>`,10)])])}const g=a(l,[["render",n]]);export{k as __pageData,g as default};
